import React from "react"
import { StaticQuery, graphql } from "gatsby"
import CenterHeader from "../CenterHeader"

const CareersTable = props => (
  <div>
    <CenterHeader>{props.title}</CenterHeader>
    <div style={{ overflowX: "auto" }}>
      <table>
        <tr>
          <th>Name</th>
          <th>Position</th>
          <th>Company</th>
          <th>Industry</th>
          <th>Location</th>
        </tr>
        {props.children}
      </table>
    </div>
  </div>
)

class CareersTables extends React.Component {
  constructor() {
    super()
    this.state = {
      year: 2019,
    }
  }

  render() {
    return (
      <StaticQuery
        query={graphql`
          {
            internships: allCareersXlsxInternships2019 {
              nodes {
                Name
                Position
                Company
                Industry
                Location
              }
            }

            fullTimeOffers: allCareersXlsxFullTimeOffers2019 {
              nodes {
                Name
                Position
                Company
                Industry
                Location
              }
            }
          }
        `}
        render={data => (
          <div>
            <CareersTable title={`${this.state.year} Internships`}>
              {data.internships.nodes.map(node => (
                <tr>
                  <td>{node.Name}</td>
                  <td>{node.Position}</td>
                  <td>{node.Company}</td>
                  <td>{node.Industry}</td>
                  <td>{node.Location}</td>
                </tr>
              ))}
            </CareersTable>
            <CareersTable title={`${this.state.year} Full Time Offers`}>
              {data.fullTimeOffers.nodes.map(node => (
                <tr>
                  <td>{node.Name}</td>
                  <td>{node.Position}</td>
                  <td>{node.Company}</td>
                  <td>{node.Industry}</td>
                  <td>{node.Location}</td>
                </tr>
              ))}
            </CareersTable>
          </div>
        )}
      />
    )
  }
}

export default CareersTables
